def sort_strings(strings):
    import re

    # Define patterns for common cases
    patterns = [
        (r'(\d+)', lambda x: int(x.group(1))),  # Numbers
        (r'(\w+)', lambda x: x.group(1).lower()),  # Words
        (r'(\w+)\s(\w+)', lambda x: (x.group(1).lower(), x.group(2).lower())),  # Two-word phrases
        (r'(\w+)\s(\w+)\s(\w+)', lambda x: (x.group(1).lower(), x.group(2).lower(), x.group(3).lower())),  # Three-word phrases
        (r'(\w+)\s(\w+)\s(\w+)\s(\w+)', lambda x: (x.group(1).lower(), x.group(2).lower(), x.group(3).lower(), x.group(4).lower()))  # Four-word phrases
    ]

    # Define a key function that applies the patterns
    def key_func(s):
        for pattern, transform in patterns:
            match = re.match(pattern, s)
            if match:
                return transform(match)
        return s.lower()

    return sorted(strings, key=key_func)

